module RefModule (
    input [4:0] weight1,
    input [4:0] weight2,
    output reg [4:0] optimized_weight1,
    output reg [4:0] optimized_weight2
);
    wire [5:0] total_weight;
      wire _n01 = weight1[0] ^ weight2[0];
  wire _c01 = weight1[0] & weight2[0];
  wire _n02 = weight1[1] ^ weight2[1] ^ _c01;
  wire _c02 = (weight1[1] & weight2[1]) | (weight1[1] & _c01) | (weight2[1] & _c01);
  wire _n03 = weight1[2] ^ weight2[2] ^ _c02;
  wire _c03 = (weight1[2] & weight2[2]) | (weight1[2] & _c02) | (weight2[2] & _c02);
  wire _n04 = weight1[3] ^ weight2[3] ^ _c03;
  wire _c04 = (weight1[3] & weight2[3]) | (weight1[3] & _c03) | (weight2[3] & _c03);
  assign total_weight = {_n01, _n02, _n03, _n04};

    always @(*) begin
        if (total_weight > 16) begin
            optimized_weight1 = (weight1 * 16) / total_weight;
            optimized_weight2 = (weight2 * 16) / total_weight;
        end else begin
            optimized_weight1 = weight1;
            optimized_weight2 = weight2;
        end
    end
endmodule
